import React, { useState, useEffect } from "react";
import api from "../api/api"; // ✅ Usamos tu instancia configurada
import Pagination from "../components/Pagination"; // ✅ Reutilizamos tu componente

const API_URL = "http://localhost:5000";

export default function Productos() {
  const [productos, setProductos] = useState([]);
  const [categorias, setCategorias] = useState([]);
  const [productoActual, setProductoActual] = useState({
    _id: null,
    nombre: "",
    descripcion: "",
    precio: "",
    stock: "",
    categoria_id: "",
    imagen: null,
  });

  const [showModal, setShowModal] = useState(false);
  const [modoEdicion, setModoEdicion] = useState(false);
  const [busqueda, setBusqueda] = useState("");
  const [imagenModal, setImagenModal] = useState(null);
  const [animarModal, setAnimarModal] = useState(false);

  // Paginación
  const [paginaActual, setPaginaActual] = useState(1);
  const productosPorPagina = 7;

  useEffect(() => {
    cargarDatos();
  }, []);

  const cargarDatos = async () => {
    try {
      const [resProd, resCat] = await Promise.all([
        api.get("/productos"),
        api.get("/categorias")
      ]);
      setProductos(resProd.data);
      setCategorias(resCat.data);
    } catch (error) {
      console.error("❌ Error al cargar datos:", error);
    }
  };

  const handleChange = (e) => {
    setProductoActual({ ...productoActual, [e.target.name]: e.target.value });
  };

  const handleFileChange = (e) => {
    setProductoActual({ ...productoActual, imagen: e.target.files[0] });
  };

  const abrirModalAgregar = () => {
    setProductoActual({
      _id: null,
      nombre: "",
      descripcion: "",
      precio: "",
      stock: "",
      categoria_id: "",
      imagen: null,
    });
    setModoEdicion(false);
    setShowModal(true);
  };

  const abrirModalEditar = (p) => {
    setProductoActual({
      _id: p._id,
      nombre: p.nombre,
      descripcion: p.descripcion,
      precio: p.precio,
      stock: p.stock,
      categoria_id: p.categoria_id?._id || p.categoria_id,
      imagen: null, 
    });
    setModoEdicion(true);
    setShowModal(true);
  };

  const guardarProducto = async (e) => {
    e.preventDefault();
    const formData = new FormData();
    // ✅ Cambiado a minúsculas para coincidir con req.body del Backend
    formData.append("nombre", productoActual.nombre);
    formData.append("descripcion", productoActual.descripcion);
    formData.append("precio", productoActual.precio);
    formData.append("stock", productoActual.stock);
    formData.append("categoria_id", productoActual.categoria_id);
    
    if (productoActual.imagen) {
      // ✅ Debe ser "imagen" para coincidir con upload.single("imagen")
      formData.append("imagen", productoActual.imagen);
    }

    try {
      if (modoEdicion) {
        await api.put(`/productos/${productoActual._id}`, formData, {
          headers: { "Content-Type": "multipart/form-data" }
        });
      } else {
        await api.post("/productos", formData, {
          headers: { "Content-Type": "multipart/form-data" }
        });
      }
      
      setShowModal(false);
      cargarDatos();
      alert("✨ Producto guardado correctamente");
    } catch (error) {
      alert("❌ Error al guardar producto");
      console.error(error);
    }
  };

  const eliminarProducto = async (id) => {
    if (window.confirm("¿Seguro que deseas eliminar este producto?")) {
      try {
        await api.delete(`/productos/${id}`);
        cargarDatos();
      } catch (error) {
        console.error("❌ Error al eliminar:", error);
      }
    }
  };

  // Lógica de búsqueda
  const productosFiltrados = productos.filter((p) => {
    const term = busqueda.toLowerCase();
    return (
      (p.nombre?.toLowerCase() || "").includes(term) ||
      (p.descripcion?.toLowerCase() || "").includes(term)
    );
  });

  // Lógica de paginación
  const productosPaginados = productosFiltrados.slice(
    (paginaActual - 1) * productosPorPagina,
    paginaActual * productosPorPagina
  );

  return (
    <div className="container mt-5">
      <div className="d-flex justify-content-between align-items-center mb-4">
        <input
          type="text"
          placeholder="🔍 Buscar producto..."
          className="form-control w-50 border-0 shadow-sm bg-light"
          value={busqueda}
          onChange={(e) => { setBusqueda(e.target.value); setPaginaActual(1); }}
        />
        <button className="btn btn-primary shadow-sm" onClick={abrirModalAgregar}>
          ➕ Nuevo Producto
        </button>
      </div>

      <div className="table-responsive shadow-sm bg-white rounded-4 overflow-hidden">
        <table className="table table-hover text-center align-middle mb-0">
          <thead className="table-dark">
            <tr>
              <th>Imagen</th>
              <th>Nombre</th>
              <th>Precio</th>
              <th>Stock</th>
              <th>Acciones</th>
            </tr>
          </thead>
          <tbody>
            {productosPaginados.map((p) => (
              <tr key={p._id}>
                <td>
                  {p.imagen ? (
                    <img
                      src={`${API_URL}/uploads/${p.imagen}`}
                      alt={p.nombre}
                      className="rounded shadow-sm"
                      style={{ width: "45px", height: "45px", objectFit: "cover", cursor: "pointer" }}
                      onClick={() => { setImagenModal(p.imagen); setAnimarModal(true); }}
                    />
                  ) : <span className="text-muted small">Sin foto</span>}
                </td>
                <td className="fw-bold">{p.nombre}</td>
                <td>${parseFloat(p.precio).toFixed(2)}</td>
                <td>
                    <span className={`badge ${p.stock < 5 ? 'bg-danger' : 'bg-primary'}`}>
                        {p.stock} un.
                    </span>
                </td>
                <td>
                  <button className="btn btn-sm btn-outline-warning me-2" onClick={() => abrirModalEditar(p)}>✏️</button>
                  <button className="btn btn-sm btn-outline-danger" onClick={() => eliminarProducto(p._id)}>🗑️</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* ✅ Usamos tu componente Pagination */}
      <Pagination 
        totalItems={productosFiltrados.length}
        itemsPerPage={productosPorPagina}
        currentPage={paginaActual}
        onPageChange={(page) => setPaginaActual(page)}
      />

      {/* MODAL CREAR/EDITAR */}
      {showModal && (
        <div className="modal show d-block" style={{ backgroundColor: "rgba(0,0,0,0.6)", backdropFilter: "blur(4px)" }}>
          <div className="modal-dialog modal-dialog-centered modal-lg">
            <div className="modal-content shadow-lg border-0 rounded-4">
              <div className="modal-header bg-primary text-white border-0">
                <h5 className="modal-title fw-bold">{modoEdicion ? "Editar Producto" : "Nuevo Producto"}</h5>
                <button className="btn-close btn-close-white" onClick={() => setShowModal(false)}></button>
              </div>
              <form onSubmit={guardarProducto}>
                <div className="modal-body p-4">
                  <div className="row g-3">
                    <div className="col-md-6">
                      <label className="form-label fw-bold small">Nombre</label>
                      <input type="text" name="nombre" value={productoActual.nombre} onChange={handleChange} className="form-control" required />
                    </div>
                    <div className="col-md-6">
                      <label className="form-label fw-bold small">Precio</label>
                      <input type="number" step="0.01" name="precio" value={productoActual.precio} onChange={handleChange} className="form-control" required />
                    </div>
                    <div className="col-md-6">
                      <label className="form-label fw-bold small">Stock</label>
                      <input type="number" name="stock" value={productoActual.stock} onChange={handleChange} className="form-control" required />
                    </div>
                    <div className="col-md-6">
                      <label className="form-label fw-bold small">Categoría</label>
                      <select name="categoria_id" value={productoActual.categoria_id} onChange={handleChange} className="form-select" required>
                        <option value="">Seleccione...</option>
                        {categorias.map(c => <option key={c._id} value={c._id}>{c.nombre}</option>)}
                      </select>
                    </div>
                    <div className="col-12">
                      <label className="form-label fw-bold small">Descripción</label>
                      <textarea name="descripcion" value={productoActual.descripcion} onChange={handleChange} className="form-control" rows="2"></textarea>
                    </div>
                    <div className="col-12">
                      <label className="form-label fw-bold small">Imagen</label>
                      <input type="file" className="form-control" onChange={handleFileChange} />
                    </div>
                  </div>
                </div>
                <div className="modal-footer border-0 p-4">
                  <button type="button" className="btn btn-light fw-bold" onClick={() => setShowModal(false)}>Cerrar</button>
                  <button type="submit" className="btn btn-primary fw-bold px-4">Guardar Cambios</button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}

      {/* MODAL ZOOM IMAGEN */}
      {imagenModal && (
        <div className={`modal fade show d-flex align-items-center justify-content-center`} 
             style={{ backgroundColor: "rgba(0,0,0,0.9)", position: "fixed", top: 0, left: 0, width: "100%", height: "100%", zIndex: 2000, opacity: animarModal ? 1 : 0, transition: '0.3s' }}
             onClick={() => { setAnimarModal(false); setTimeout(() => setImagenModal(null), 300); }}>
          <img src={`${API_URL}/uploads/${imagenModal}`} alt="Zoom" className="img-fluid rounded-4 shadow-lg" style={{ maxHeight: "85vh", transform: animarModal ? 'scale(1)' : 'scale(0.8)', transition: '0.3s' }} />
        </div>
      )}
    </div>
  );
}
